components.customDefaultValue:
const formView = sessionStorage.getItem('formview');
if (formView === 'true') {
  setTimeout(function() {

    const skipTypes = [
      'button', 'panel', 'columns', 'column', 'table',
      'well', 'tabs', 'fieldset', 'datagrid', 'editgrid',
      'container', 'form'
    ];

    const excludeKeys = ['printButton', 'header_home_button_5'];

    function disableComponent(comp) {
      const type = comp.component ? comp.component.type : comp.type;
      const key  = comp.component ? comp.component.key  : comp.key;
      if (!skipTypes.includes(type) && !excludeKeys.includes(key)) {
        comp.component.disabled = true;
        comp.disabled = true;
      }
    }

    // ყველა კომპონენტი
    instance.root.everyComponent(function(comp) {
      disableComponent(comp);
    });

    // table-ების rows -> cells -> components
    instance.root.everyComponent(function(comp) {
      if (comp.type === 'table' && comp.rows) {
        comp.rows.forEach(function(row) {
          row.forEach(function(cell) {
            if (cell.components) {
              cell.components.forEach(function(c) {
                disableComponent(c);
              });
            }
          });
        });
      }
    });

  }, 0);
}
value = formView || '';

